    AcordionA(tipo="a" clase-tarjeta="tarjeta bg1" data-aos="fade-down")
      .row.justify-content-center(titulo="Paso 1. Trazo del delantero")
        .col-lg-7
          h5 A. Base del patrón 
          ul.lista-ul--color.ico-lista.fa-lista.mb-4
            li 
              i.fas.fa-angle-right
              span Partir del patrón básico delantero infantil previamente elaborado. 
