                  td.text-bold.text-center 5
                  td.text-start Corte de entalle 1. 
                  td.text-start Desde la línea de copa hasta el bajo, marcar 1,5 cm de ancho, trazando línea recta vertical. 
                tr.bgt-2
                  td.text-bold.text-center 6
                  td.text-start Corte de entalle 2. 
                  td.text-start Repetir en costado opuesto con línea recta vertical de 1,5 cm de ancho.   
                tr.bgt-1
                  td.text-bold.text-center 7
                  td.text-start Dobladillo inferior = 3 cm.
                  td.text-start Añadir margen en la base de la manga para terminación. 
                tr.bgt-2
                  td.text-bold.text-center 8
                  td.text-start Revisión final. 
                  td.text-start Verificar que la longitud del bajo coincida con el contorno de muñeca (22 - 24 cm aprox. en talla media infantil). 
